// https://www.kibo-ui.com/components/code-block

import type {BundledLanguage} from 'shiki';

import {
  CodeBlockBody,
  CodeBlockContent,
  CodeBlockCopyButton,
  CodeBlockFilename,
  CodeBlockFiles,
  CodeBlockHeader,
  CodeBlockItem,
  CodeBlock as CodeBlockOrig,
} from './code-block-index';

export function CodeBlock({
  language,
  code,
  filename = '',
  copy = true,
}: {
  language: BundledLanguage;
  code: string;
  filename?: string;
  copy?: boolean;
}) {
  return (
    <CodeBlockOrig data={[{language, code, filename}]} defaultValue={language}>
      {(filename || copy) && (
        <CodeBlockHeader>
          <CodeBlockFiles>
            {item => (
              <CodeBlockFilename key={item.language} value={item.language}>
                {item.filename}
              </CodeBlockFilename>
            )}
          </CodeBlockFiles>
          <CodeBlockCopyButton />
        </CodeBlockHeader>
      )}
      <CodeBlockBody>
        {item => (
          <CodeBlockItem key={item.language} value={item.language}>
            <CodeBlockContent language={item.language}>
              {item.code}
            </CodeBlockContent>
          </CodeBlockItem>
        )}
      </CodeBlockBody>
    </CodeBlockOrig>
  );
}
